React 컴포넌트 예시입니다.

```tsx
// 인사 컴포넌트
import { useState } from "react";

interface 인사Props {
  이름: string;
}

export function 인사카드({ 이름 }: 인사Props) {
  const [인사횟수, 인사횟수설정] = useState(0);

  const 인사하기 = () => {
    인사횟수설정(이전 => 이전 + 1);
  };

  return (
    <div className="p-4 rounded-lg border">
      <h2 className="text-lg font-bold">안녕하세요, {이름}님!</h2>
      <p className="text-sm text-gray-500">인사 횟수: {인사횟수}번</p>
      <button
        onClick={인사하기}
        className="mt-2 px-4 py-2 bg-blue-500 text-white rounded"
      >
        인사하기
      </button>
    </div>
  );
}
```

TypeScript + Tailwind CSS를 사용한 기본 컴포넌트입니다.

FastAPI로 간단한 API를 만드는 방법입니다.

```python
# main.py
from fastapi import FastAPI

app = FastAPI()

# GET 요청
@app.get("/")
def 메인():
    return {"메시지": "화랑 API에 오신 것을 환영합니다!"}

# POST 요청
@app.post("/인사")
def 인사하기(이름: str):
    return {"인사": f"안녕하세요, {이름}님!"}

# 실행: uvicorn main:app --reload
```

실행 후 `http://localhost:8000/docs`에서 API 문서를 확인할 수 있습니다.
